(101011, 'BMN.001', 'Menerima dan mencatat Barang Milik Negara ke aplikasi Simak BMN sesuai dengan prosedur yang berlaku guna kelancaran dalam pendokumentasian BMN.', 0, 0, 0, NULL, 0),
(101011, 'BMN.002', 'Menginputkan data BMN ke dalam aplikasi SIMAN sesuai ketentuan yang berlaku guna kelancaran proses koordinasi.', 0, 0, 0, NULL, 0),
(101011, 'BMN.003', 'Mendata dan memberi kode Barang Milik Negara sesuai dengan jenis dan macam barang untuk tertib administrasi dan inventarisasi barang.', 0, 0, 0, NULL, 0),
(101011, 'BMN.004', 'Menyiapkan bahan catatan akhir laporan BMN sesuai dengan ketentuan yang berlaku untuk kelancaran pelaksanaan tugas.', 0, 0, 0, NULL, 0),
(101011, 'BMN.005', 'Menyiapkan bahan rekonsiliasi data Rencana Kebutuhan BMN dengan Kantor Pusat Badan Nasional Pencarian dan Pertolongan sesuai dengan ketentuan yang berlaku guna kelancaran pelaksanaan tugas.', 0, 0, 0, NULL, 0),
(101011, 'BMN.006', 'Menyiapkan bahan inventarisasi Barang Milik Negara di lingkungan Kantor Pencarian dan Pertolongan untuk mempermudah dalam proses pencarian BMN.', 0, 0, 0, NULL, 0),
(101011, 'BMN.007', 'Menganalisis dan menyiapkan bahan pengajuan proses penghapusan dan lelang Aset Negara Kantor Pencarian dan Pertolongan sesuai dengan prosedur dan ketentuan yang berlaku untuk menilai harga barang milik negara.', 0, 0, 0, NULL, 0),
(101011, 'BMN.008', 'Menyiapkan bahan permohonan penetapan status penggunaan barang milik negara  sesuai dengan ketentuan yang berlaku guna kelancaran pelaksanaan tugas.', 0, 0, 0, NULL, 0),
(101011, 'BMN.009', 'Menyiapkan bahan administrasi persediaan pada buku persediaan, kartu barang, kartu transaksi sesuai dengan ketentuan yang berlaku guna tertib administrasi barang milik negara.', 0, 0, 0, NULL, 0),
(101011, 'BMN.010', 'Menyusun daftar barang ruangan, daftar barang lainnya dan kartu inventaris barang dan mencatat mutasi/perpindahan barang antar ruangan sesuai dengan ketentuan yang berlaku guna kelancaran pelaksanaan tugas.', 0, 0, 0, NULL, 0),
(101011, 'BMN.011', 'Melaporkan hasil pelaksanaan tugas sesuai dengan prosedur dan peraturan yang berlaku kepada atasan sebagai bentuk pertanggung jawaban dalam pelaksanaan tugas.', 0, 0, 0, NULL, 0),
(101011, 'BMN.012', 'Melakukan tugas kedinasan lain yang diberikan pimpinan baik lisan maupun tertulis.', 0, 0, 0, NULL, 0),
(103013, 'DRV.001', 'Memeriksa kelengkapan kendaraan dengan cara mengecek rem, oli dan lampu di mesin, air radiator, air aki dan tekanan udara ban sesuai dengan prosedur agar kendaraan dapat dikendarai dengan baik.', 0, 0, 0, NULL, 0),
(103013, 'DRV.002', 'Memanaskan mesin kendaraan dengan rutin sesuai dengan jadwal  guna kelancaran dalam pemakaian kendaraan.', 0, 0, 0, NULL, 0),
(103013, 'DRV.003', 'Merawat kendaraan dengan cara membersihkan mesin, ruangan dalam dan luar kendaraan sesuai dengan jadwal agar kendaraan terawat dan terpelihara.', 0, 0, 0, NULL, 0),
(103013, 'DRV.004', 'Mengemudikan kendaraan berdasarkan tujuan dan ketentuan lalu lintas yang berlaku agar kendaraan dapat tiba di tujuan dengan selamat.', 0, 0, 0, NULL, 0),
